import json
import os
from collections import deque, OrderedDict
from typing import Dict, Any, Optional, Iterator, List

class MemTable:
    """In-memory component holding recent writes."""
    def __init__(self):
        # Use OrderedDict to maintain insertion order for simplicity, though standard dict is often enough.
        # Format: {key: (value, deletion_flag)}
        self._data: Dict[str, tuple] = {}

    def put(self, key: str, value: Any) -> None:
        """Inserts or updates a key-value pair."""
        self._data[key] = (value, False) # Not deleted

    def delete(self, key: str) -> None:
        """Marks a key for deletion using a tombstone."""
        if key in self._data:
            self._data[key] = (None, True) # Tombstone set

    def get(self, key: str) -> Optional[Any]:
        """Retrieves the value associated with the key from MemTable."""
        if key in self._data and not self._data[key][1]:
            return self._data[key][0]
        return None

    @property
    def items(self) -> Iterator[tuple[str, Any]]:
        """Yields (key, value) pairs that are available on the MemTable."""
        result = []
        for key, (value, is_deleted) in self._data.items():
            if not is_deleted:
                result.append((key, value))
        return iter(result)

    def dump(self) -> Dict[str, tuple]:
        """Returns the underlying dictionary representation for flushing/testing."""
        return dict(self._data)

class SSTable:
    """Represents a sorted collection of key-value pairs stored on disk."""
