        self.storage_path = storage_path

    @classmethod
    def load(cls, path: str) -> 'SSTable':
        """Loads data from a serialized file."""
        return cls(path)

    def write_to_disk(self, records: Dict[str, tuple]) -> None:
        """Writes key-value pairs to disk. Expects sorted input suitable for serialization."""
        # Simple JSON dump for simulation. Real LSM trees use specialized formats (e.g., SSTable index/data blocks).
        with open(self.storage_path, 'w') as f:
            json.dump(records, f)
        print(f"SSTable written to {self.storage_path}")

    @classmethod
    def read_from_disk(cls, path: str) -> Dict[str, tuple]:
        """Reads data from disk."""
        try:
            with open(path, 'r') as f:
                return json.load(f)
        except FileNotFoundError:
            print(f"File not found at {path}")
            return {}

