        """Removes the local SSTable file."""
        if os.path.exists(self.storage_path):
            os.remove(self.storage_path)

class LSMTree:
    """Simplified Log-Structured Merge Tree Key-Value Store."""
    def __init__(self, directory: str = "lsm_data"):
        self.directory = directory
        # In-memory write buffer
        self.memtable = MemTable()
        # Sorted list of SSTable paths (L0 -> L1 -> ...)
        self.levels: List[List[str]] = [[]]  # Level 0 initially
        self._initialize_directory()

    def _get_level(self, level: int) -> Optional[list[SSTable]]:
        """Helper to get iterable SSTables for a given level."""
        if level >= len(self.levels):
            return None
        ssts = []
        for path in self.levels[level]:
            # We use the path string as an identifier here, and load it dynamically.
            ssts.append(SSTable(path))
        return ssts

    def _initialize_directory(self):
        """Ensures the storage directory exists."""
        os.makedirs(self.directory, exist_ok=True)

    def put(self, key: str, value: Any) -> None:
        """Inserts or updates a key-value pair, writing to MemTable."""
        # Level 0 is where all writes start
        self.memtable.put(key, value)

    def get(self, key: str) -> Optional[Any]:
        """Retrieves the value from the most recent source (MemTable first)."""
        # Check MemTable (L0 buffer)
        value = self.memtable.get(key)
        if value is not None:
            return value

        # Iterate through SSTables in descending order of level index (highest to lowest)
        for level_index in range(len(self.levels) - 1, -1, -1):
            sstables = self._get_level(level_index)
            if sstables:
                # In a real system, we'd optimize reads across all files at this level.
                # Here, we load and check them sequentially (naive read).
                for sstable in sstables:
                    data = sstable.read_from_disk()
                    if key in data:
                        value, is_deleted = data[key]
                        if not is_deleted:
                            return value

        # If no value found anywhere
        return None

