        """Marks a key as deleted (sets tombstone in MemTable)."""
        # Deletes are always handled by setting a tombstone in the next write buffer.
        self.memtable.delete(key)

    def keys(self) -> List[str]:
        """Returns all keys currently known to the LSMTree."""
        all_keys = set()

        # 1. Keys from MemTable
        for key, (value, is_deleted) in self.memtable._data.items():
            if not is_deleted:
                all_keys.add(key)
            elif value is None and is_deleted: # Only count keys that are definitively marked deleted
                 # Note: For simplicity, we might just track existence, but for correctness in get(), 
                 # simply adding the key to the set tracking all known keys works if 'get' handles tombstones properly.
                all_keys.add(key) # Track keys that existed/are marked deleted

        # 2. Keys from SSTables (Collect unique keys present across all levels)
        for level_index in range(len(self.levels)):
            sstables = self._get_level(level_index)
            if sstables:
                for sstable in sstables:
                    data = sstable.read_from_disk()
                    for key, (value, is_deleted) in data.items():
                        # Key exists if it's even present in the file, regardless of current status
                        all_keys.add(key)

        return sorted(list(all_keys))


