        """Writes MemTable contents to a new SSTable file."""
        temp_filename = f"l0_{len(self.levels)}_{os.getpid()}_{hash(str(self.memtable.dump()))}.json"
        file_path = os.path.join(self.directory, temp_filename)

        # Exclude tombstones from the data dump if they are not meant to be persistent state, 
        # but since we need them for correctness in reads/compacts, we must serialize them correctly.
        dumped_data = self.memtable.dump()

        sstable = SSTable(file_path)
        sstable.write_to_disk(dumped_data)

        return file_path

    def compact(self):
        """Merges MemTable and all SSTables into a clean new set of SSTables."""
        print("\n--- Starting Compaction ---")
        all_data: Dict[str, tuple] = {} # Key -> (Value, IsDeleted)

        # 1. Merge from MemTable
        temp_memtable = self.memtable.dump()
        for key, (value, is_deleted) in temp_memtable.items():
             all_data[key] = (value, is_deleted)

        # 2. Merge from all live SSTables
        current_sstables: List[SSTable] = []
        for level_index in range(len(self.levels)):
            if not self.levels[level_index]:
                continue
            for path in self.levels[level_index]:
                sstable = SSTable(path)
                current_sstables.append(sstable)

        for sstable in current_sstables:
            data = sstable.read_from_disk()
            for key, (value, is_deleted) in data.items():
                 # The highest priority record wins during compaction (Last write/most recent delete)
                all_data[key] = (value, is_deleted)


        if not all_data:
             print("Compaction skipped: No data to merge.")
             return

        # 3. Overwrite existing SSTables at Level 0 with the merged result

        # Clean up old data first (Crucial for correct compaction simulation)
        for path in self.levels[0]:
            SSTable(path).delete_file()
        self.levels[0] = [] # Clear list, we will rebuild it

        # Write the merged results into a new L0 file structure representation
        temp_filename = f"l0_compacted_{os.getpid()}.json"
        new_file_path = os.path.join(self.directory, temp_filename)
        new_sstable = SSTable(new_file_path)
        new_sstable.write_to_disk(all_data)

        # Update internal state to point to the new file and drop the old one's references if applicable
        self.levels[0] = [new_file_path] 
        print("Compaction successful. Merged data into L0.")


    def flush(self):
        """Writes MemTable contents to a new SSTable and promotes it to Level 0."""
        if not self.memtable._data:
            return None

        # 1. Write the current memtable content to disk (creating a new SSTable)
        new_path = self._flush_memtable_to_sstable()

        # 2. Update internal tracking structure
        self.levels[0].append(new_path)

        # 3. Clear the MemTable buffer after successful flush (Simulating commit)
        self.memtable.__init__()
        print("MemTable successfully flushed and L0 updated.")


    def cleanup_temp_files(self):
        """Removes all generated SSTable files for clean testing."""
        for level in self.levels:
            for path in level:
                SSTable(path).delete_file()
        print("\nCleaned up temporary storage directory.")

